const body        = $input.first().json;
const vars        = $('LocalVariables').first().json;
const userMessage = (body.chatInput || body.message || body.input || '').trim();
const sessionId   = body.sessionId || $uuid();
const requestId   = $uuid();

// User info — injected by frontend or use defaults for testing
const personId  = body.person_id  || '204319';
const role      = (body.role      || 'employee').toLowerCase();
const waName    = body.full_name  || body.wa_name || 'Mohammed Ali';
const msgType   = (body.msg_type  || 'TEXT').toUpperCase();
const messageId = body.message_id || $uuid();

// Language detection: Arabic unicode block
const arabicPattern = /[\u0600-\u06FF]/;
const detectedLang  = arabicPattern.test(userMessage) ? 'ar' : 'en';

// Fast-path: greeting check
const greetingsEn = vars.QUICK_GREETINGS_EN.split(',');
const greetingsAr = vars.QUICK_GREETINGS_AR.split(',');
const normalized  = userMessage.toLowerCase();

const isGreeting =
  msgType === 'TEXT' &&
  userMessage.length < 30 &&
  (
    greetingsEn.some(g => normalized === g || normalized.startsWith(g + ' ')) ||
    greetingsAr.some(g => userMessage.includes(g))
  );

return [{
  json: {
    userMessage, sessionId, requestId,
    personId, role, waName, msgType, messageId,
    detectedLang,
    fastPath: isGreeting ? 'GREETING' : null
  }
}];

const s    = $('InitSession').first().json;
const name = s.waName.split(' ')[0];
const lang = s.detectedLang;
const msg  = s.userMessage.toLowerCase();

let reply;
if (lang === 'ar') {
  if (msg.includes('شكرا') || msg.includes('شكراً')) {
    reply = `على الرحب والسعة ${name}! 🇦🇪 هل تحتاج أي مساعدة أخرى؟`;
  } else if (msg.includes('مع السلامة') || msg.includes('وداعا')) {
    reply = `مع السلامة ${name}! نتمنى لك يوماً طيباً. 🇦🇪`;
  } else {
    reply = `أهلاً ${name}! 🇦🇪 كيف يمكنني مساعدتك اليوم؟`;
  }
} else {
  if (msg.includes('thank')) {
    reply = `You're welcome, ${name}! Let me know if you need anything else. 🇦🇪`;
  } else if (msg.includes('bye') || msg.includes('goodbye')) {
    reply = `Goodbye, ${name}! Have a great day. 🇦🇪`;
  } else {
    reply = `Hello ${name}! 👋 How can I assist you today?`;
  }
}

return [{
  json: {
    ...s,
    ai_response: reply,
    ai_reason: 'Greeting|FastPath',
    conversation_state: 'complete'
  }
}];

const s           = $('InitSession').first().json;
const agentOutput = $input.first().json;
const outputText  = agentOutput.output || agentOutput.text || '';

return [{
  json: {
    person_id:          s.personId,
    session_id:         s.sessionId,
    request_id:         s.requestId,
    message_id:         s.messageId,
    role:               s.role,
    full_name:          s.waName,
    language:           s.detectedLang,
    msg_type:           s.msgType,
    user_message:       s.userMessage,
    ai_response:        outputText,
    ai_reason:          'agent_processed',
    conversation_state: 'complete',
    agent_used:         'FAHR_AI_AGENT'
  }
}];

const s = $('FastPathGreeting').first().json;

return [{
  json: {
    person_id:          s.personId,
    session_id:         s.sessionId,
    request_id:         s.requestId,
    message_id:         s.messageId,
    role:               s.role,
    full_name:          s.waName,
    language:           s.detectedLang,
    msg_type:           s.msgType,
    user_message:       s.userMessage,
    ai_response:        s.ai_response,
    ai_reason:          s.ai_reason,
    conversation_state: s.conversation_state,
    agent_used:         'FastPath'
  }
}];
